mapper.sql:
WHERE rr.deleted = 0

    AND (sp.student_no LIKE CONCAT('%', #{query.studentKeyword}, '%')
      OR sp.chinese_name LIKE CONCAT('%', #{query.studentKeyword}, '%')
      OR sp.english_name LIKE CONCAT('%', #{query.studentKeyword}, '%'))


    AND rr.renewal_type = #{query.renewalType}


    AND rr.renewal_status = #{query.renewalStatus}


    AND rr.application_date >= #{query.startDate}


    AND rr.application_date <= #{query.endDate}
